    Ok(())
}

enum State {
    Init,
    Running,
    Done,
}

impl State {
    fn next(self) -> Result<Self, &'static str> {
        match self {
            State::Init => Ok(State::Running),
            State::Running => Ok(State::Done),
            State::Done => Err("Unexpected state transition")
        }
    }
}

